using System;

class Program
{
    static void Main()
    {
        Console.Write("Enter a day number (1-7): ");
        int day = int.Parse(Console.ReadLine());

        string dayName = day switch
        {
            1 => "Monday",
            2 => "Tuesday",
            3 => "Wednesday",
            4 => "Thursday",
            5 => "Friday",
            6 => "Saturday",
            7 => "Sunday",
            _ => "Invalid day"
        };

        Console.WriteLine(dayName);
    }
}
